                "config_name": "Zora - search configuration with...",
                "config_description": "SELECT\n    p.\"kbc_project\",\n    p.\"kbc_project_url\",\n    p.\"kbc_project_id\",\n    conf.\"kbc_component_configuration_id\",\n    confrow.\"kbc_component_configuration_row_id\",\n     conf.\"token_name\",\n     -- confrow.\"configuration_row_json\", conf.\"configuration_json\", -- if I want to see the JSON itself\n    COUNT(DISTINCT j.\"kbc_job_id\") AS jobs_count -- how many jobs in that time period\nFROM \"kbc_project\" p\nJOIN \"kbc_component_configuration\" conf\n    ON p.\"kbc_project_id\" = conf.\"kbc_project_id\"\nJOIN \"kbc_job\" j\n    ON j.\"kbc_component_configuration_id\" = conf.\"kbc_component_configuration_id\"\nLEFT JOIN \"kbc_component_configuration_row\" confrow\n    ON confrow.\"kbc_component_configuration_id\" = conf.\"kbc_component_configuration_id\"\nWHERE TRY_TO_TIMESTAMP(j.\"job_created_at\") BETWEEN '2025-06-30' AND '2025-07-02'-- when the config was active - there were some runs\n  AND (\n      (\n          LOWER(conf.\"configuration_json\") LIKE '% what I a am searching for %'\n          AND LOWER(conf.\"configuration_json\") LIKE '% what I a am searching for %'\n      )\n      OR (\n          LOWER(confrow.\"configuration_row_json\") LIKE '% what I a am searching for %'\n          AND LOWER(confrow.\"configuration_row_json\") LIKE '% what I a am searching for %'\n      )\n  )\n  AND \n    confrow.\"kbc_configuration_row_is_deleted\" = 'false' -- to have only existing rows\nGROUP BY p.\"kbc_project\", conf.\"token_name\", p.\"kbc_project_url\", p.\"kbc_project_id\", conf.\"token_name\", conf.\"kbc_component_configuration_id\", confrow.\"kbc_component_configuration_row_id\"\n--, confrow.\"configuration_row_json\", conf.\"configuration_json\" -- if I want to see the JSON itself",
